function solve(nums1) {
    const n = nums1.length;

    // Strategy: Check if we can make all elements odd, OR if we can make all elements even.

    // Helper function to check feasibility for a target parity (0 for even, 1 for odd)
    const checkFeasibility = (targetParity) => {
        // For each element nums1[i], we need to find a choice such that the result
        // has the targetParity.

        // The choices for nums2[i] are:
        // 1. nums1[i] (Parity is nums1[i] % 2)
        // 2. nums1[i] - nums1[j] (where j != i and nums1[i] - nums1[j] >= 1)
        //    The parity is (nums1[i] - nums1[j]) % 2, which is (nums1[i] % 2 - nums1[j] % 2) % 2

        // Let p_i = nums1[i] % 2.
        // Choice 1 parity: p_i
        // Choice 2 parity: (p_i - p_j) % 2

        // We need to determine if for every i, there exists a valid choice resulting in targetParity.

        for (let i = 0; i < n; i++) {
            const p_i = nums1[i] % 2;
            let canSatisfy = false;

            // Check Choice 1: nums2[i] = nums1[i]
            if (p_i === targetParity) {
                canSatisfy = true;
            }

            if (!canSatisfy) {
                // Check Choice 2: nums2[i] = nums1[i] - nums1[j] (j != i, diff >= 1)
                for (let j = 0; j < n; j++) {
                    if (i === j) continue;

                    const diff = nums1[i] - nums1[j];
                    if (diff >= 1) {
                        // Parity of difference: (p_i - p_j) mod 2
                        const p_j = nums1[j] % 2;
                        // (p_i - p_j) % 2 might be negative if p_j > p_i.
                        // A safe way for modular arithmetic of difference:
                        // (p_i - p_j + 2) % 2
                        const diffParity = (p_i - p_j + 2) % 2;

                        if (diffParity === targetParity) {
                            canSatisfy = true;
                            break;
                        }
                    }
                }
            }

            if (!canSatisfy) {
                return false; // Cannot satisfy targetParity for index i
            }
        }
        return true; // Satisfies targetParity for all indices
    };

    // Check if all can be made odd (targetParity = 1)
    const canBeAllOdd = checkFeasibility(1);
    if (canBeAllOdd) return true;

    // Check if all can be made even (targetParity = 0)
    const canBeAllEven = checkFeasibility(0);
    if (canBeAllEven) return true;

    return false;
}

